/** Parent Cass of HL7 Error
 * @since 1.0.0 */
declare class HL7Error extends Error {
    code: number;
    /** @internal */
    constructor(code: number, message: string);
}
/** Used to indicate a fatal failure of a connection.
 * @since 1.0.0 */
declare class HL7FatalError extends HL7Error {
    /** @internal */
    name: string;
    constructor(message: string);
}
/** Used to indicate a fatal failure of a connection.
 * @since 1.0.0 */
declare class HL7ParserError extends Error {
    /** @internal */
    name: string;
}
export { HL7Error, HL7FatalError, HL7ParserError };
